def _auto_install():
    """تثبيت جميع المكتبات المطلوبة تلقائياً"""
    import subprocess as _sp, sys as _sys
    required = ["flask"]
    for _pkg in required:
        try:
            __import__(_pkg)
        except ImportError:
            print(f"[SETUP] جاري تثبيت {_pkg} ...")
            _sp.check_call([_sys.executable, "-m", "pip", "install",
                            "--quiet", "--no-cache-dir", _pkg])
            print(f"[SETUP] ✓ {_pkg} تم تثبيته بنجاح")

_auto_install()

from flask import Flask, request, jsonify, Response

app = Flask(__name__)

