#              قاعدة البيانات المحلية (ملفات JSON)
# ═══════════════════════════════════════════════════════

DATA_DIR  = os.path.join(os.path.dirname(os.path.abspath(__file__)), "data")
DB_SECRET = "ZIAD -host-2026-secret"
os.makedirs(DATA_DIR, exist_ok=True)


def db_read(col: str) -> list:
    path = os.path.join(DATA_DIR, col + ".json")
    try:
        with open(path, "r", encoding="utf-8") as f:
            return json.load(f)
    except Exception:
        return []


def db_write(col: str, data: list) -> None:
    path = os.path.join(DATA_DIR, col + ".json")
    with open(path, "w", encoding="utf-8") as f:
        json.dump(data, f, ensure_ascii=False, indent=2)


def new_id() -> str:
    return uuid.uuid4().hex[:24]


# ═══════════════════════════════════════════════════════
#              نظام التوثيق (JWT بسيط بدون مكتبات خارجية)
# ═══════════════════════════════════════════════════════

def make_token(payload: dict) -> str:
    data = base64.b64encode(json.dumps(payload).encode()).decode()
    sig  = _hmac.new(DB_SECRET.encode(), data.encode(), hashlib.sha256).hexdigest()
    return data + "." + sig


def verify_token(token: str):
    if not token:
        return None
    dot = token.rfind(".")
    if dot == -1:
        return None
    data, sig = token[:dot], token[dot + 1:]
    expected  = _hmac.new(DB_SECRET.encode(), data.encode(), hashlib.sha256).hexdigest()
    if sig != expected:
        return None
    try:
        return json.loads(base64.b64decode(data).decode())
    except Exception:
        return None


def get_uid(req) -> str | None:
    auth  = req.headers.get("Authorization", "")
    token = auth[7:] if auth.startswith("Bearer ") else ""
    p = verify_token(token)
    return p["uid"] if p else None


# ═══════════════════════════════════════════════════════
#              مساعد الاستعلام (WHERE / ORDER / LIMIT)
# ═══════════════════════════════════════════════════════

def apply_query(docs: list, args) -> list:
    result = list(docs)

    for w in args.getlist("w"):
        parts = w.split("|", 2)
        if len(parts) != 3:
            continue
        field, op, val_json = parts
        try:
            val = json.loads(val_json)
        except Exception:
            val = val_json

        def make_filter(f, o, v):
            def flt(d):
                dv = d.get(f)
                if o == "==":              return dv == v
                if o == "!=":              return dv != v
                if o == ">":               return dv is not None and dv > v
                if o == "<":              return dv is not None and dv < v
                if o == ">=":             return dv is not None and dv >= v
                if o == "<=":             return dv is not None and dv <= v
                if o == "array-contains": return isinstance(dv, list) and v in dv
                return True
            return flt

        result = list(filter(make_filter(field, op, val), result))

    for ob in args.getlist("ob"):
        parts = ob.split("|", 1)
        field = parts[0]
        desc  = len(parts) > 1 and parts[1] == "desc"
        result.sort(
            key=lambda d, f=field: (d.get(f) is None, d.get(f) or ""),
            reverse=desc
        )

    lim = args.get("lim")
    if lim:
        try:
            result = result[: int(lim)]
        except Exception:
            pass

    return result


def parse_path(segs: list) -> dict:
    if len(segs) == 1:
        return dict(col=segs[0])
    if len(segs) == 2:
        return dict(col=segs[0], doc_id=segs[1])
    if len(segs) == 3:
        return dict(col=segs[2], parent_filter=segs[0] + "/" + segs[1])
    if len(segs) >= 4:
        return dict(col=segs[2], doc_id=segs[3], parent_filter=segs[0] + "/" + segs[1])
    return dict(col=segs[-1])


