@app.route("/api/auth/register", methods=["POST"])
def auth_register():
    body     = request.get_json() or {}
    email    = (body.get("email") or "").strip()
    password = body.get("password") or ""
    if not email or not password:
        return jsonify(dict(code="auth/missing-fields", message="بيانات ناقصة")), 400
    users = db_read("users")
    if any(u["email"] == email for u in users):
        return jsonify(dict(code="auth/email-already-in-use",
                            message="البريد الإلكتروني مستخدم بالفعل.")), 400
    if len(password) < 6:
        return jsonify(dict(code="auth/weak-password",
                            message="كلمة المرور ضعيفة جداً (6 أحرف على الأقل).")), 400
    pwd_hash = hashlib.sha256((password + DB_SECRET).encode()).hexdigest()
    uid  = new_id()
    now  = datetime.utcnow().isoformat()
    user = dict(id=uid, uid=uid, email=email,
                displayName=email.split("@")[0],
                photoURL="", plan="free", balance=0,
                role="user", createdAt=now, passwordHash=pwd_hash)
    users.append(user)
    db_write("users", users)
    safe = {k: v for k, v in user.items() if k != "passwordHash"}
    return jsonify(dict(token=make_token(dict(uid=uid, email=email)), user=safe))


@app.route("/api/auth/login", methods=["POST"])
def auth_login():
    body     = request.get_json() or {}
    email    = (body.get("email") or "").strip()
    password = body.get("password") or ""
    if not email or not password:
        return jsonify(dict(code="auth/missing-fields", message="بيانات ناقصة")), 400
    users = db_read("users")
    user  = next((u for u in users if u["email"] == email), None)
    if not user:
        return jsonify(dict(code="auth/invalid-credential",
                            message="البريد الإلكتروني أو كلمة المرور غير صحيحة.")), 401
    pwd_hash = hashlib.sha256((password + DB_SECRET).encode()).hexdigest()
    if pwd_hash != user.get("passwordHash"):
        return jsonify(dict(code="auth/invalid-credential",
                            message="البريد الإلكتروني أو كلمة المرور غير صحيحة.")), 401
    uid  = user["uid"]
    safe = {k: v for k, v in user.items() if k != "passwordHash"}
    return jsonify(dict(token=make_token(dict(uid=uid, email=email)), user=safe))


@app.route("/api/auth/me", methods=["GET"])
def auth_me():
    uid = get_uid(request)
    if not uid:
        return jsonify(dict(message="Unauthorized")), 401
    users = db_read("users")
    user  = next((u for u in users if u.get("uid") == uid), None)
    if not user:
        return jsonify(dict(message="User not found")), 404
    safe = {k: v for k, v in user.items() if k != "passwordHash"}
    return jsonify(safe)


@app.route("/api/auth/profile", methods=["PATCH"])
def auth_profile():
    uid = get_uid(request)
    if not uid:
        return jsonify(dict(message="Unauthorized")), 401
    body  = request.get_json() or {}
    users = db_read("users")
    idx   = next((i for i, u in enumerate(users) if u.get("uid") == uid), -1)
    if idx == -1:
        return jsonify(dict(message="User not found")), 404
    for key in ("displayName", "photoURL"):
        if key in body:
            users[idx][key] = body[key]
    db_write("users", users)
    safe = {k: v for k, v in users[idx].items() if k != "passwordHash"}
    return jsonify(safe)


