@app.route("/api/db/<path:db_path>", methods=["GET"])
def db_get(db_path):
    segs          = [s for s in db_path.split("/") if s]
    p             = parse_path(segs)
    col           = p.get("col")
    doc_id        = p.get("doc_id")
    parent_filter = p.get("parent_filter")
    docs          = db_read(col)
    if parent_filter:
        docs = [d for d in docs if d.get("_parent") == parent_filter]
    if doc_id:
        found = next((d for d in docs if d.get("id") == doc_id), None)
        return (jsonify(found) if found else (jsonify(dict(message="Not found")), 404))
    return jsonify(apply_query(docs, request.args))


@app.route("/api/db/<path:db_path>", methods=["POST"])
def db_post(db_path):
    segs          = [s for s in db_path.split("/") if s]
    p             = parse_path(segs)
    col           = p.get("col")
    parent_filter = p.get("parent_filter")
    body          = request.get_json() or {}
    doc_id        = new_id()
    now           = datetime.utcnow().isoformat()
    new_doc       = dict(id=doc_id, **body)
    if "createdAt" not in new_doc:
        new_doc["createdAt"] = now
    if parent_filter:
        new_doc["_parent"] = parent_filter
    docs = db_read(col)
    docs.append(new_doc)
    db_write(col, docs)
    return jsonify(dict(id=doc_id))


@app.route("/api/db/<path:db_path>", methods=["PUT"])
def db_put(db_path):
    segs          = [s for s in db_path.split("/") if s]
    p             = parse_path(segs)
    col           = p.get("col")
    doc_id        = p.get("doc_id")
    parent_filter = p.get("parent_filter")
    if not doc_id:
        return jsonify(dict(message="Doc ID required")), 400
    body    = request.get_json() or {}
    new_doc = dict(id=doc_id, **body)
    if parent_filter:
        new_doc["_parent"] = parent_filter
    docs = db_read(col)
    idx  = next((i for i, d in enumerate(docs) if d.get("id") == doc_id), -1)
    if idx != -1:
        docs[idx] = new_doc
    else:
        docs.append(new_doc)
    db_write(col, docs)
    return jsonify(dict(id=doc_id))


@app.route("/api/db/<path:db_path>", methods=["PATCH"])
def db_patch(db_path):
    segs   = [s for s in db_path.split("/") if s]
    p      = parse_path(segs)
    col    = p.get("col")
    doc_id = p.get("doc_id")
    if not doc_id:
        return jsonify(dict(message="Doc ID required")), 400
    body = request.get_json() or {}
    docs = db_read(col)
    idx  = next((i for i, d in enumerate(docs) if d.get("id") == doc_id), -1)
    if idx == -1:
        return jsonify(dict(message="Not found")), 404
    docs[idx].update(body)
    db_write(col, docs)
    return jsonify(dict(id=doc_id))


@app.route("/api/db/<path:db_path>", methods=["DELETE"])
def db_delete(db_path):
    segs   = [s for s in db_path.split("/") if s]
    p      = parse_path(segs)
    col    = p.get("col")
    doc_id = p.get("doc_id")
    if not doc_id:
        return jsonify(dict(message="Doc ID required")), 400
    docs = db_read(col)
    docs = [d for d in docs if d.get("id") != doc_id]
    db_write(col, docs)
    return jsonify(dict(deleted=True))


