_processes = {}
_plock     = threading.Lock()


def _add_log(server_id: str, message: str) -> None:
    with _plock:
        if server_id not in _processes:
            return
        ts    = datetime.now().strftime("%H:%M:%S")
        lines = message.split("\n")
        for line in lines:
            if line.strip() or len(lines) == 1:
                _processes[server_id]["logs"].append(f"[{ts}] {line}")
        if len(_processes[server_id]["logs"]) > 2000:
            _processes[server_id]["logs"] = _processes[server_id]["logs"][-2000:]


@app.route("/api/health")
def health():
    return jsonify(dict(status="ok"))


@app.route("/api/logs/<server_id>")
def get_logs(server_id):
    with _plock:
        data = dict(_processes.get(server_id, {}))
    if not data:
        return jsonify(dict(message="No process found")), 404
    return jsonify(dict(logs=data.get("logs", [])))


@app.route("/api/stop", methods=["POST"])
def stop_process():
    body      = request.get_json() or {}
    server_id = body.get("serverId")
    with _plock:
        data = _processes.get(server_id)
    if data:
        proc = data.get("process")
        if proc:
            try:
                proc.kill()
            except Exception:
                pass
        with _plock:
            _processes.pop(server_id, None)
        return jsonify(dict(status="stopped"))
    return jsonify(dict(status="not_running"))


@app.route("/api/execute", methods=["POST"])
def execute():
    body      = request.get_json() or {}
    files     = body.get("files", [])
    main      = body.get("main", "main.py")
    server_id = body.get("serverId")

    if not server_id:
        return jsonify(dict(message="Server ID is required")), 400

    with _plock:
        old = _processes.get(server_id)
        if old and old.get("process"):
            try:
                old["process"].kill()
            except Exception:
                pass
        _processes[server_id] = {
            "process": None,
            "logs": [
                "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━",
                "  ZIAD  HOST — Python Execution Engine",
                f"  الملف الرئيسي: {main}",
                "━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━",
                "[SYSTEM] جاري تهيئة البيئة..."
            ]
        }

    threading.Thread(
        target=_run_python,
        args=(server_id, files, main),
        daemon=True
    ).start()

    return jsonify(dict(status="started"))


def _run_python(server_id: str, files: list, main: str) -> None:
    temp_dir = tempfile.mkdtemp(prefix=f"ZIAD -{server_id}-")
    try:
        for f in files:
            fpath = os.path.join(temp_dir, f["name"])
            os.makedirs(os.path.dirname(fpath), exist_ok=True)
            with open(fpath, "w", encoding="utf-8") as fh:
                fh.write(f.get("content", ""))

        env = {**os.environ, "PYTHONUNBUFFERED": "1"}

        _add_log(server_id, "[SYSTEM] إنشاء البيئة الافتراضية (venv)...")
        python_exe = sys.executable
        venv_dir   = os.path.join(temp_dir, "venv")
        pip_exe    = python_exe

        try:
            subprocess.run(
                [python_exe, "-m", "venv", venv_dir],
                check=True, capture_output=True, timeout=60
            )
            _add_log(server_id, "[SYSTEM] تم إنشاء البيئة الافتراضية.")
            bin_dir    = "Scripts" if sys.platform == "win32" else "bin"
            python_exe = os.path.join(venv_dir, bin_dir, "python" + (".exe" if sys.platform == "win32" else ""))
            pip_exe    = os.path.join(venv_dir, bin_dir, "pip" + (".exe" if sys.platform == "win32" else ""))
            env["VIRTUAL_ENV"] = venv_dir
            env["PATH"]        = os.path.dirname(python_exe) + os.pathsep + env.get("PATH", "")
            subprocess.run(
                [pip_exe, "install", "--upgrade", "pip", "setuptools", "wheel"],
                capture_output=True, cwd=temp_dir, timeout=120
            )
        except Exception as exc:
            _add_log(server_id, f"[SYSTEM] تحذير venv: {exc} — جاري استخدام Python الرئيسي")
            pip_exe = python_exe

        req_file = next((f for f in files if f["name"] == "requirements.txt"), None)
        if req_file:
            _add_log(server_id, "[SYSTEM] جاري تثبيت requirements.txt...")
            try:
                result = subprocess.run(
                    [pip_exe, "install", "--no-cache-dir", "-r", "requirements.txt"],
                    cwd=temp_dir, capture_output=True, text=True, timeout=300
                )
                if result.returncode == 0:
                    _add_log(server_id, "[SYSTEM] تم تثبيت المتطلبات بنجاح.")
                else:
                    _add_log(server_id, "[SYSTEM] فشل التثبيت الجماعي — جاري التثبيت فرداً...")
                    for line in req_file["content"].split("\n"):
                        line = line.strip()
                        if line and not line.startswith("#"):
                            r = subprocess.run(
                                [pip_exe, "install", "--no-cache-dir", line],
                                cwd=temp_dir, capture_output=True, text=True, timeout=120
                            )
                            status = "" if r.returncode == 0 else ""
                            _add_log(server_id, f"[SYSTEM] {status} {line}")
            except Exception as e:
                _add_log(server_id, f"[ERROR] خطأ في تثبيت المتطلبات: {e}")
        else:
            content = " ".join(f.get("content", "") for f in files)
            lib_map = [
                (r"import\s+telegram|from\s+telegram", "python-telegram-bot"),
                (r"import\s+requests",                  "requests"),
                (r"import\s+flask|from\s+flask",       "flask"),
                (r"import\s+discord|from\s+discord",   "discord.py"),
                (r"import\s+aiogram|from\s+aiogram",   "aiogram"),
                (r"import\s+pandas",                    "pandas"),
                (r"import\s+numpy",                     "numpy"),
                (r"import\s+PIL|from\s+PIL",           "Pillow"),
                (r"import\s+bs4|from\s+bs4",           "beautifulsoup4"),
                (r"import\s+pyrogram|from\s+pyrogram", "pyrogram tgcrypto"),
                (r"import\s+telethon|from\s+telethon", "telethon"),
                (r"import\s+aiohttp|from\s+aiohttp",   "aiohttp"),
                (r"import\s+httpx|from\s+httpx",       "httpx"),
                (r"import\s+sqlalchemy",                "sqlalchemy"),
                (r"import\s+pymongo|from\s+pymongo",   "pymongo"),
            ]
            for pattern, pkg in lib_map:
                if re.search(pattern, content):
                    _add_log(server_id, f"[SYSTEM] كشف تلقائي — تثبيت: {pkg}")
                    try:
                        r = subprocess.run(
                            [pip_exe, "install", "--no-cache-dir"] + pkg.split(),
                            cwd=temp_dir, capture_output=True, text=True, timeout=180
                        )
                        status = "" if r.returncode == 0 else ""
                        _add_log(server_id, f"[SYSTEM] {status} {pkg}")
                    except Exception:
                        pass

        _add_log(server_id, f"[SYSTEM] ━━━━━━ بدء تشغيل {main} ━━━━━━")
        proc = subprocess.Popen(
            [python_exe, main],
            cwd=temp_dir,
            env=env,
            stdout=subprocess.PIPE,
            stderr=subprocess.PIPE,
            text=True,
            bufsize=1
        )

        with _plock:
            if server_id in _processes:
                _processes[server_id]["process"] = proc

        def _reader(stream, prefix=""):
            for line in iter(stream.readline, ""):
                _add_log(server_id, prefix + line.rstrip())
            stream.close()

        t_out = threading.Thread(target=_reader, args=(proc.stdout,),           daemon=True)
        t_err = threading.Thread(target=_reader, args=(proc.stderr, "[ERROR] "), daemon=True)
        t_out.start()
        t_err.start()

        proc.wait()
        t_out.join(timeout=5)
        t_err.join(timeout=5)

        code = proc.returncode
        _add_log(server_id, f"[SYSTEM] ━━━━━━ انتهى التنفيذ (كود الخروج: {code}) ━━━━━━")
        time.sleep(60)
        with _plock:
            if _processes.get(server_id, {}).get("process") is proc:
                _processes.pop(server_id, None)

    except Exception as exc:
        _add_log(server_id, f"[ERROR] {exc}")
    finally:
        shutil.rmtree(temp_dir, ignore_errors=True)


